using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json.Serialization;
using Microsoft.Extensions.AI;

namespace ResearchAgent.Tools;

public sealed class WebSearchTool
{
    private readonly HttpClient _httpClient = new();

    [Description("Searches the web for information on a given query. Returns a list of relevant results with titles, snippets, and URLs.")]
    public async Task<string> SearchWeb(
        [Description("The search query to look up on the web")] string query)
    {
        Console.WriteLine($"  🔍 Searching: \"{query}\"");

        try
        {
            // Use DuckDuckGo Instant Answer API (no key required)
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";

            var response = await _httpClient.GetFromJsonAsync<DuckDuckGoResponse>(url);

            if (response is null)
                return "No results found.";

            var results = new List<string>();

            if (!string.IsNullOrWhiteSpace(response.Abstract))
            {
                results.Add($"**{response.Heading}**\n{response.Abstract}\nSource: {response.AbstractUrl}");
            }

            foreach (var topic in response.RelatedTopics?.Take(5) ?? [])
            {
                if (!string.IsNullOrWhiteSpace(topic.Text))
                {
                    results.Add($"- {topic.Text}\n  URL: {topic.FirstUrl}");
                }
            }

            if (results.Count == 0)
                return $"No detailed results found for \"{query}\". Try a different search query.";

            Console.WriteLine($"  ✅ Found {results.Count} results");
            return string.Join("\n\n", results);
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}. Try a different query.";
        }
    }

    private sealed class DuckDuckGoResponse
    {
        [JsonPropertyName("Abstract")]
        public string? Abstract { get; set; }

        [JsonPropertyName("AbstractUrl")]
        public string? AbstractUrl { get; set; }

        [JsonPropertyName("Heading")]
        public string? Heading { get; set; }

        [JsonPropertyName("RelatedTopics")]
        public List<RelatedTopic>? RelatedTopics { get; set; }
    }

    private sealed class RelatedTopic
    {
        [JsonPropertyName("Text")]
        public string? Text { get; set; }

        [JsonPropertyName("FirstURL")]
        public string? FirstUrl { get; set; }
    }
}

using System.ComponentModel;
using Microsoft.Extensions.AI;

namespace ResearchAgent.Tools;

public sealed class NoteTakingTool
{
    private readonly List<ResearchNote> _notes = [];

    public IReadOnlyList<ResearchNote> Notes => _notes;

    [Description("Saves an important research finding as a note. Use this to record key facts, statistics, or insights discovered during research.")]
    public string TakeNote(
        [Description("A concise title for this note")] string title,
        [Description("The detailed content of the note")] string content,
        [Description("The source URL or reference where this information was found")] string source)
    {
        var note = new ResearchNote(title, content, source, DateTime.UtcNow);
        _notes.Add(note);
        Console.WriteLine($"  📝 Note saved: \"{title}\"");
        return $"Note #{_notes.Count} saved: \"{title}\"";
    }

    [Description("Retrieves all research notes collected so far. Use this to review findings before writing a summary.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes have been taken yet.";

        var formatted = _notes.Select((n, i) =>
            $"[Note {i + 1}] {n.Title}\n  Content: {n.Content}\n  Source: {n.Source}");

        Console.WriteLine($"  📋 Retrieved {_notes.Count} notes");
        return string.Join("\n\n", formatted);
    }
}

public sealed record ResearchNote(string Title, string Content, string Source, DateTime Timestamp);

