using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using OpenAI;
using ResearchAgent.Tools;

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to run the research agent.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

var builder = Host.CreateApplicationBuilder(args);

builder.Services.AddChatClient(pipeline => pipeline
    .UseFunctionInvocation()
    .UseOpenAIChatClient(modelId, new OpenAIClient(apiKey)));

var host = builder.Build();
var chatClient = host.Services.GetRequiredService<IChatClient>();

// Initialize tools
var webSearch = new WebSearchTool();
var noteTaking = new NoteTakingTool();

var tools = new List<AITool>
{
    AIFunctionFactory.Create(webSearch.SearchWeb),
    AIFunctionFactory.Create(noteTaking.TakeNote),
    AIFunctionFactory.Create(noteTaking.GetNotes),
};

// Get topic from user
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();

if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\n🔬 Researching: {topic}\n");

var chatOptions = new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 2048,
    Tools = tools,
};

var messages = new List<ChatMessage>
{
    new(ChatRole.System, """
        You are a thorough research agent. Your job is to research the given topic using available tools.

        Follow these steps:
        1. Search the web 2-3 times with different queries to gather diverse information
        2. Take notes on the most important findings (include sources)
        3. Review your collected notes
        4. Provide a well-structured summary with key findings and sources

        Be systematic and cite your sources. If a search returns limited results, try rephrasing the query.
        """),
    new(ChatRole.User, $"Please research the following topic and provide a comprehensive summary: {topic}"),
};

Console.WriteLine("Agent working...\n");

var response = await chatClient.GetResponseAsync(messages, chatOptions);

Console.WriteLine("\n════════════════════════════════════════");
Console.WriteLine("  RESEARCH SUMMARY");
Console.WriteLine("════════════════════════════════════════\n");
Console.WriteLine(response.Text);

if (noteTaking.Notes.Count > 0)
{
    Console.WriteLine("\n────────────────────────────────────────");
    Console.WriteLine("  COLLECTED NOTES");
    Console.WriteLine("────────────────────────────────────────");
    foreach (var note in noteTaking.Notes)
    {
        Console.WriteLine($"\n  📌 {note.Title}");
        Console.WriteLine($"     {note.Content}");
        Console.WriteLine($"     Source: {note.Source}");
    }
}

Console.WriteLine("\n✅ Research complete.");

