+    [Description("Searches the web for information on a given query. Returns a list of relevant results with titles, snippets, and URLs.")]
+    public async Task<string> SearchWeb(
+        [Description("The search query to look up on the web")] string query)
+    {
+        Console.WriteLine($"  🔍 Searching: \"{query}\"");
+
+        try
+        {
+            // Use DuckDuckGo Instant Answer API (no key required)
+            var encoded = Uri.EscapeDataString(query);
+            var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";
+
+            var response = await _httpClient.GetFromJsonAsync<DuckDuckGoResponse>(url);
+
+            if (response is null)
+                return "No results found.";
+
+            var results = new List<string>();
+
+            if (!string.IsNullOrWhiteSpace(response.Abstract))
+            {
+                results.Add($"**{response.Heading}**\n{response.Abstract}\nSource: {response.AbstractUrl}");
+            }
+
+            foreach (var topic in response.RelatedTopics?.Take(5) ?? [])
+            {
+                if (!string.IsNullOrWhiteSpace(topic.Text))
+                {
+                    results.Add($"- {topic.Text}\n  URL: {topic.FirstUrl}");
+                }
+            }
+
+            if (results.Count == 0)
+                return $"No detailed results found for \"{query}\". Try a different search query.";
+
+            Console.WriteLine($"  ✅ Found {results.Count} results");
+            return string.Join("\n\n", results);
+        }
+        catch (Exception ex)
+        {
+            return $"Search failed: {ex.Message}. Try a different query.";
+        }
+    }
+
