using System.ComponentModel;
using Microsoft.Extensions.AI;

namespace ResearchAgent.Tools;

public sealed class NoteTakingTool
{
    private readonly List<ResearchNote> _notes = [];

    public IReadOnlyList<ResearchNote> Notes => _notes;

    [Description("Saves an important research finding as a note. Use this to record key facts, statistics, or insights discovered during research.")]
    public string TakeNote(
        [Description("A concise title for this note")] string title,
        [Description("The detailed content of the note")] string content,
        [Description("The source URL or reference where this information was found")] string source)
    {
        var note = new ResearchNote(title, content, source, DateTime.UtcNow);
        _notes.Add(note);
        Console.WriteLine($"  📝 Note saved: \"{title}\"");
        return $"Note #{_notes.Count} saved: \"{title}\"";
    }

    [Description("Retrieves all research notes collected so far. Use this to review findings before writing a summary.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes have been taken yet.";

        var formatted = _notes.Select((n, i) =>
            $"[Note {i + 1}] {n.Title}\n  Content: {n.Content}\n  Source: {n.Source}");

        Console.WriteLine($"  📋 Retrieved {_notes.Count} notes");
        return string.Join("\n\n", formatted);
    }
}

public sealed record ResearchNote(string Title, string Content, string Source, DateTime Timestamp);

