 IChatClient chatClient = new ChatClientBuilder(new OpenAIClient(apiKey).GetChatClient(modelId).AsIChatClient())
     .UseFunctionInvocation()
     .Build();

 // Initialize tools
 var webSearch = new WebSearchTool();
 var noteTaking = new NoteTakingTool();

 var tools = new List<AITool>
 {
     AIFunctionFactory.Create(webSearch.SearchWeb),
     AIFunctionFactory.Create(noteTaking.TakeNote),
     AIFunctionFactory.Create(noteTaking.GetNotes),
 };

 // Get topic from user
 Console.Write("Enter a research topic: ");
 var topic = Console.ReadLine()?.Trim();

 if (string.IsNullOrEmpty(topic))
 {
     Console.WriteLine("No topic provided. Exiting.");
     return;
 }

